onClick:
{{
(async () => {

  if (!inpMotivoReversionPA.text?.trim()) {

    showAlert(
      "Debe indicar el motivo de la reversión.",
      "warning"
    );

    return;

  }

  if (!inpClaveReversoPA.text?.trim()) {

    showAlert(
      "Debe indicar la contraseña.",
      "warning"
    );

    return;

  }

  await qryPAValidarClaveReverso.run();

  if (qryPAValidarClaveReverso.data?.[0]?.clave_valida !== 1) {

    showAlert(
      "La contraseña es incorrecta.",
      "error"
    );

    return;

  }

  await qryPAReversar.run();

  closeModal("mdlAnularPA");

  resetWidget("inpClaveReversoPA", true);
  resetWidget("inpMotivoReversionPA", true);

  await qryPAConsultar.run();

  resetWidget("tblConsultaPA", true);

  showAlert(
    "Pago " +
      qryPAReversar.data?.[0]?.numero_pago +
      " reversado correctamente.",
    "success"
  );

})().catch(e => {

  showAlert(
    e.message,
    "error"
  );

});
}}
